import React, { useState } from 'react';
import axios from 'axios';
import './ProfessorPage.css'; // Vom folosi un CSS comun

const CreateAssignment: React.FC = () => {
    const [asstitle, setAsstitle] = useState('');
    const [description, setDescription] = useState('');
    const [message, setMessage] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setMessage('');

        const token = localStorage.getItem('token');
        const professorId = localStorage.getItem('userId');

        if (!professorId || !token) {
            setMessage('Eroare: Nu sunteți autentificat.');
            setIsLoading(false);
            return;
        }

        try {
            // 1. Pregătim DTO-ul pentru backend
            const createRequest = {
                asstitle,
                description,
                professorId: parseInt(professorId) // Convertim ID-ul în număr
            };

            // 2. Apelăm noul endpoint de creare
            await axios.post('http://localhost:8080/api/assignments/create', createRequest, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

            setMessage('Tema a fost creată cu succes!');
            // 3. Resetăm formularul
            setAsstitle('');
            setDescription('');

        } catch (error) {
            setMessage('A apărut o eroare la crearea temei.');
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="create-assignment-container">
            <h3>Creează o Temă Nouă</h3>
            <form onSubmit={handleSubmit}>
                <div className="form-group-prof">
                    <label htmlFor="title">Titlu Temă:</label>
                    <input
                        id="title"
                        type="text"
                        value={asstitle}
                        onChange={(e) => setAsstitle(e.target.value)}
                        required
                    />
                </div>
                <div className="form-group-prof">
                    <label htmlFor="description">Descriere:</label>
                    <textarea
                        id="description"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        required
                    />
                </div>
                <button type="submit" className="create-button" disabled={isLoading}>
                    {isLoading ? 'Se publică...' : 'Publică Tema'}
                </button>
                {message && <p className="form-message">{message}</p>}
            </form>
        </div>
    );
};

export default CreateAssignment;
